// Parse Bessemer + slice batch based on offset (v2.7)
const html = $('Browserless Bessemer').first().json.data || $('Browserless Bessemer').first().json.content || '';
const offsetData = $('Get Bessemer Offset').first().json;
const currentOffset = parseInt(offsetData.records?.[0]?.fields?.Value || '0', 10);
const BATCH_SIZE = 25;

const allCompanies = [];
const vcName = 'Bessemer Venture Partners';
const seenSlugs = new Set();
const seenNames = new Set();

const companyPattern = /href=["']https?:\/\/(?:www\.)?bvp\.com\/companies\/([a-z0-9-]+)["'][^>]*>([^<]*)</gi;
let match;

while ((match = companyPattern.exec(html)) !== null) {
  const slug = match[1].trim().toLowerCase();
  let name = match[2].trim();

  if (!slug || slug.length < 2 || slug === 'companies' || slug === 'all') continue;
  if (seenSlugs.has(slug)) continue;
  seenSlugs.add(slug);

  if (!name || name.length < 2) {
    name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  }

  name = name.replace(/^\s*[-\u2022]\s*/, '').trim();
  if (!name || name.length < 2 || name.length > 60) continue;

  const normalizedName = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seenNames.has(normalizedName)) continue;
  seenNames.add(normalizedName);

  allCompanies.push({
    company_name: name,
    company_url: 'https://www.bvp.com/companies/' + slug,
    description: name + ' - Bessemer Venture Partners portfolio company',
    source: vcName
  });
}

const totalCompanies = allCompanies.length;
const batch = allCompanies.slice(currentOffset, currentOffset + BATCH_SIZE);
const newOffset = (currentOffset + BATCH_SIZE >= totalCompanies) ? 0 : currentOffset + BATCH_SIZE;
const isComplete = newOffset === 0 && currentOffset > 0;

console.log(`Bessemer: ${totalCompanies} total, offset ${currentOffset}, batch size ${batch.length}, new offset ${newOffset}`);

return batch.map(company => ({
  json: {
    ...company,
    _meta: {
      totalCompanies,
      currentOffset,
      newOffset,
      isComplete,
      source: 'bessemer'
    }
  }
}));

// Get the new offset from the first item's metadata
const items = $('Parse Bessemer Batch').all();
const meta = items[0]?.json?._meta || {};
return [{ json: { newOffset: meta.newOffset || 0, recordId: 'recOSBqsKAUMSHS1k' } }];

